const ahora = new Date();
const fecha = ahora.toISOString().slice(0,10).replace(/-/g,'');
const rand = Math.floor(Math.random() * 9000 + 1000);
const ticket_id = `TD-${fecha}-${rand}`;

// Soporta body anidado (webhook) o directo
const body = $input.first().json.body || $input.first().json;

// El formulario envía: tipo, canal, nombre, documento, correo, telefono,
// descripcion, contacto_preferido, confirmacion_correo, sin_correo
const tipo_pqr = body.tipo || body.tipo_pqr || 'peticion';

// Mapear canal de contacto preferido
const canal_raw = body.canal || body.contacto_preferido || body.canal_contacto || 'formulario_web';
const canal_map = {
  'whatsapp': 'whatsapp',
  'correo':   'correo',
  'llamada':  'telefono',
  'formulario_web': 'formulario_web',
};
const canal_contacto = canal_map[canal_raw] || canal_raw;

return [{
  json: {
    ticket_id,
    nombre:             body.nombre          || 'Anónimo',
    correo:             body.correo          || body.confirmacion_correo || '',
    telefono:           body.telefono        || '',
    documento:          body.documento       || '',
    tipo_pqr,
    descripcion:        body.descripcion     || '',
    canal_contacto,
    contacto_preferido: body.contacto_preferido || canal_raw,
    sin_correo:         body.sin_correo      || false,
    origen:             'formulario_web',
    estado:             'pendiente',
    prioridad:          'media',
    acuse_enviado:      false,
    notif_agente:       false,
  }
}];
